mapper.select:
select r.*, c.content_text as content_title, c.content_text as content_text, c.anonymous_id as target_anonymous_id, cm.comment_text as comment_text, cm.anonymous_id as comment_anonymous_id from report r left join content c on r.target_type = 1 and r.target_id = c.id left join comment cm on r.target_type = 2 and r.target_id = cm.id
and (r.anonymous_id like concat('%', #{search}, '%') or r.report_type like concat('%', #{search}, '%') or r.report_desc like concat('%', #{search}, '%') or c.content_text like concat('%', #{search}, '%') or cm.comment_text like concat('%', #{search}, '%'))
and r.handle_status = #{handleStatus}
and r.target_type = #{targetType}
order by r.create_time desc limit #{offset}, #{limit}

select count(*) from report r left join content c on r.target_type = 1 and r.target_id = c.id left join comment cm on r.target_type = 2 and r.target_id = cm.id
and (r.anonymous_id like concat('%', #{search}, '%') or r.report_type like concat('%', #{search}, '%') or r.report_desc like concat('%', #{search}, '%') or c.content_text like concat('%', #{search}, '%') or cm.comment_text like concat('%', #{search}, '%'))
and handle_status = #{handleStatus}
and target_type = #{targetType}
